VALUES
  ('heelevel3-53250add-moex-00232', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["甲飲酒駕駛汽車，為警攔查，發現其吐氣酒精濃度超過規定標準，經裁罰新臺幣10萬元； 而涉刑事犯罪部分，另經法院判處罰金新臺幣3萬元，基於從輕原則，監理機關依法不可 事後再裁決命甲補繳納新臺幣7萬元", "行政罰之裁處權時效，因天災、事變或依法律規定不能開始或進行裁處時，應停止其進行", "乙同一行為違反同一行政法上義務，A、B機關均有管轄權，因A機關處理在先，因此依 法應由A機關管轄該案件", "行政機關執行行政罰職務之人員，應向違反行政法規定之行為人出示其執行職務之證明文 件，並告知其所違反之法規 33350"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00233', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '行政執行法有關行政執行即時強制之規定，下列敘述何者錯誤？', '["對於執行機關所為損失補償之決定不服者，得依法提起國家賠償", "軍器、凶器及其他危險物，為預防危害之必要，得扣留之", "對於住宅、建築物或其他處所之進入，以人民之生命、身體、財產有迫切之危害，非進入 不能救護者為限", "人民因執行機關依法實施即時強制，致其生命、身體或財產遭受特別損失時，得請求補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00234', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '有關政府資訊公開法之敘述，下列何者錯誤？', '["合議制機關之會議紀錄，原則上應主動公開", "政府機關提供政府資訊時，得向申請人收取費用", "政府機關作成意思決定前，內部單位之擬稿原則上不公開或提供", "申請人對於政府機關就其申請提供政府資訊所為之決定不服者，不得提起行政救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00235', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '依訴願法規定，下列何者得提起撤銷訴願？', '["請求確認法規命令無效遭拒絕", "對已執行拆除完畢之建物拆除處分", "對已繳納執行完畢之罰鍰處分", "申請公務員迴避遭行政機關駁回"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00236', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於訴願決定之敘述，下列何者錯誤？', '["訴願決定確定後，就該事件，有拘束原處分機關之效力", "訴願決定確定後，就受委託行使公權力之事件，受委託行使公權力之團體或個人受其拘束", "原行政處分經撤銷後，原行政處分機關須重為處分者，應依訴願決定意旨為之，並將處理 情形以書面告知受理訴願機關", "內政部之行政處分，經行政院訴願決定撤銷，內政部為確認其處分是否合法，得向行政法 院提起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00237', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於行政訴訟法上停止執行制度之敘述，下列何者錯誤？', '["行政法院認原處分之執行，將發生難以回復之損害，且有急迫情事者，得裁定停止執行", "訴訟繫屬中行政處分以不停止執行為原則", "行政法院裁定停止執行前，原處分機關已依職權停止執行者，應為駁回聲請之裁定", "於行政訴訟起訴前，行政法院不得依聲請裁定停止執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00238', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '關於我國行政訴訟制度之訴訟案件管轄，下列敘述何者錯誤？', '["因不動產徵收、徵用或撥用之訴訟，專屬不動產所在地之行政法院管轄", "重新審理之聲請專屬最高行政法院管轄", "交通裁決事件原則上以高等行政法院為終審法院", "定行政法院之管轄以起訴時為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00239', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '依司法院釋字第469號解釋，有關國家賠償之成立，下列敘述何者錯誤？', '["公務員依法對特定人民負有作為義務而已無不作為之裁量餘地，倘故意過失怠於執行職務 時，有國家賠償之適用", "公務員在裁量收縮至零之情況下違反法律規定，此違法不僅是客觀法秩序違反，容有公權 利侵害之可能", "透過新保護規範理論，得探究系爭規定是否於立法目的上有保護特定之當事人，以為其主 張救濟之依據", "國家賠償之請求權限於法律明確規定特定人享有向行政機關為一定作為之請求權者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00240', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-3082b5f1', 'sub-heelevel3-53250add-03', NULL, 'single_choice', '下列何者非屬損失補償之適用範圍？', '["主管機關勘查測量風景區範圍，進入私人土地造成農作物或地上物毀損", "私有古蹟或歷史建築坐落於第三人土地上，限制土地所有權使用收益", "學童依法律接種疫苗後發生嚴重疾病或身心障礙", "農民依主管機關行政指導休耕某作物後，因該作物價格暴漲，造成農民損失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:05+00:00", "source_pdf_sha1": "af29d1a29a79", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "333", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('heelevel3-53250add-moex-00241', 'heelevel3-53250add', 'heelevel3-53250add-moex-111-cfe42432', 'sub-heelevel3-53250add-05', NULL, 'essay', '行政院農業委員會（簡稱農委會）發現 A船的船主甲雇用的船長乙，駕
